// Agent Heartbeat Store
// POST  /webhook/agent-heartbeat  body: {agentId, agentName, action, summary?, outcome?}
// GET   /webhook/agent-heartbeat?action=read[&limit=50]
const MAX_HEARTBEATS = 500;  // keep last 500
const sd = $getWorkflowStaticData('global');
sd.heartbeats = sd.heartbeats || [];

const input = $input.first().json || {};
const q = input.query || {};
const body = input.body || {};

// READ
if (q.action === 'read' || (!body.agentId && !body.action)) {
  const limit = Math.min(parseInt(q.limit || '50'), 200);
  // Reverse-chronological (most recent first)
  const recent = (sd.heartbeats || []).slice(-limit).reverse();
  // 24h stats
  const cutoff24 = Date.now() - 24*3600*1000;
  const recent24 = (sd.heartbeats || []).filter(h => new Date(h.at).getTime() >= cutoff24);
  const byAgent = {};
  for (const h of recent24) {
    byAgent[h.agentId] = byAgent[h.agentId] || { total: 0, action_taken: 0, no_op: 0, errored: 0 };
    byAgent[h.agentId].total += 1;
    if (h.outcome === 'action_taken') byAgent[h.agentId].action_taken += 1;
    else if (h.outcome === 'no_op') byAgent[h.agentId].no_op += 1;
    else if (h.outcome === 'error') byAgent[h.agentId].errored += 1;
  }
  return [{ json: { ok: true, heartbeats: recent, stats_24h: byAgent, total_24h: recent24.length } }];
}

// WRITE
const heartbeat = {
  at: new Date().toISOString(),
  agentId: body.agentId || '',
  agentName: body.agentName || '',
  action: body.action || 'fired',
  summary: (body.summary || '').toString().slice(0, 200),
  outcome: body.outcome || 'unknown'   // action_taken | no_op | error
};
sd.heartbeats.push(heartbeat);
if (sd.heartbeats.length > MAX_HEARTBEATS) {
  sd.heartbeats = sd.heartbeats.slice(-MAX_HEARTBEATS);
}
return [{ json: { ok: true, total: sd.heartbeats.length } }];

